+    } else if area.height >= 9 {
+        2
+    } else {
+        0
+    };
+    if area.height.saturating_sub(query_h) < 3 {
+        query_h = 0;
+    }
+    let (query_area, event_area) = split_top(area, query_h);
+
+    if query_h > 0 {
+        render_dashboard_query_bar(
+            frame,
+            query_area,
+            query_input,
+            query_active,
+            query_text,
+            db_snapshot,
+            entries,
+        );
+    }
+
+    if event_area.height >= 3 {
+        render_event_log(
+            frame,
+            event_area,
+            viewer,
+            entries,
+            scroll_offset,
+            auto_follow,
+            quick_filter,
+            verbosity,
+            inline_anomaly_count,
+            effects_enabled,
+        );
+    }
+}
