+    if last_active_micros <= 0 {
+        return ('○', tp.activity_stale);
+    }
+    let elapsed = now_micros.saturating_sub(last_active_micros);
+    if elapsed < AGENT_ACTIVE_THRESHOLD_MICROS {
+        ('●', tp.activity_active)
+    } else if elapsed < AGENT_IDLE_THRESHOLD_MICROS {
+        ('●', tp.activity_idle)
+    } else {
+        ('○', tp.activity_stale)
+    }
+}
